import{_ as r,o as t,c as o,a2 as a}from"./chunks/framework.DX8nTkPK.js";const g=JSON.parse('{"title":"Early Service","description":"","frontmatter":{},"headers":[],"relativePath":"coremod/early-service.md","filePath":"coremod/early-service.md","lastUpdated":1778766727000}'),d={name:"coremod/early-service.md"};function n(c,e,i,l,s,h){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="early-service" tabindex="-1">Early Service <a class="header-anchor" href="#early-service" aria-label="Permalink to &quot;Early Service&quot;">​</a></h1><p>Early Service 是 ModLauncher 在 <strong>SERVICE Layer</strong> 中加载的一组特殊 SPI 服务。之所以称为 &quot;Early&quot;，是因为常规 Mod 使用的 Service 位于 PLUGIN Layer，加载时机较晚；而这组 Service 在更早的阶段即被加载，因此得名。</p><p>以下列表定义于 <code>net.neoforged.fml.loading.TransformerDiscovererConstants</code>（<code>ITransformerDiscoveryService</code> 的实现可引用该常量类），<strong>仅供参考，取决于实际版本</strong>：</p><table tabindex="0"><thead><tr><th>全限定类名</th><th>用途</th></tr></thead><tbody><tr><td><code>cpw.mods.modlauncher.api.ITransformationService</code></td><td>类变换服务，在类加载阶段修改字节码</td></tr><tr><td><code>net.neoforged.neoforgespi.locating.IModFileCandidateLocator</code></td><td>定位并发现所有候选 Mod 文件</td></tr><tr><td><code>net.neoforged.neoforgespi.locating.IModFileReader</code></td><td>读取并解析 Mod 文件内容</td></tr><tr><td><code>net.neoforged.neoforgespi.locating.IDependencyLocator</code></td><td>解析 Mod 依赖关系</td></tr><tr><td><code>net.neoforged.neoforgespi.earlywindow.GraphicsBootstrapper</code></td><td>图形引导，初始化渲染环境</td></tr><tr><td><code>net.neoforged.neoforgespi.earlywindow.ImmediateWindowProvider</code></td><td>早期窗口，在 Minecraft 主窗口出现前提供临时窗口</td></tr></tbody></table><hr><h2 id="jar-in-jar-限制" tabindex="-1">Jar-in-Jar 限制 <a class="header-anchor" href="#jar-in-jar-限制" aria-label="Permalink to &quot;Jar-in-Jar 限制&quot;">​</a></h2><p>由于 ModLauncher 和 FML 的模块化分层设计，<strong>Early Service 无法通过 Jar-in-Jar 的方式被访问</strong>。如果 Coremod 同时需要提供 Early Service 和普通 Mod，必须将 Early Service 放在外层 JAR，将 Mod 本体放在内层 JAR，并自行编写 <code>IModFileCandidateLocator</code> 来手动加载内层 Mod。</p><details class="details custom-block"><summary>开发环境的特殊情况</summary><p>在开发环境（IDE 直接运行）中，正在开发的 Mod 通常不以 JAR 形式存在，而是作为 classpath 上的目录或单个 class 文件。这种形态走的是 FML 的 <strong>开发环境加载路径</strong>，与生产环境的 JAR 加载路径不同——类加载和模块发现的过程更为扁平。</p><p>因此在某些情况下，开发环境中可以实现 Early Service 和普通 Mod 共存于同一模块，且不会触发模块重复导出的异常。但这属于开发环境的特殊行为，<strong>不可依赖它作为正式方案</strong>。</p><p>Jar-in-Jar 的限制仅在 <strong>生产环境</strong>（打包后的 JAR）中实际生效。</p></details><hr><h2 id="是否需要自行编写-locator" tabindex="-1">是否需要自行编写 Locator <a class="header-anchor" href="#是否需要自行编写-locator" aria-label="Permalink to &quot;是否需要自行编写 Locator&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本区间</th><th>是否需要自行编写 Locator</th></tr></thead><tbody><tr><td>1.20.6 ~ 1.21.8（PR <a href="https://github.com/neoforged/FancyModLoader/pull/375" target="_blank" rel="noreferrer">#375</a> 之前）</td><td>需要</td></tr><tr><td>PR <a href="https://github.com/neoforged/FancyModLoader/pull/375" target="_blank" rel="noreferrer">#375</a> 合并之后</td><td>不再需要</td></tr></tbody></table><blockquote><p>各版本对应的 NeoForge 版本及 Locator 编写细节后续补充。</p></blockquote>',12)])])}const f=r(d,[["render",n]]);export{g as __pageData,f as default};
